import React, { useState } from "react";
import {connect} from 'react-redux'
import userActions from '../redux/actions/userActions'
import Box from '@mui/material/Box'
import MailIcon from '@mui/icons-material/Mail'
import KeyIcon from '@mui/icons-material/Key'
import Typography from '@mui/material/Typography'
import {Link as LinkRouter} from "react-router-dom"
import GoogleSignIn from "../components/GoogleSignIn";
import '../styles/signin-up.css'

function SignIn(props) {
    const [email, setEmail] = useState("")
    const [password , setPassword] = useState("")

    const handleSubmit = async (event) => {
        event.preventDefault()
        const logedUser = {
            email: email,
            password: password,
            from: "form-Signin",
        }
        await props.signInUser(logedUser)
    }

    return ( 
                    <div className="signin-upbody">
                        <div className="form-container">
                        <Typography variant="h2" className='input' sx={{padding: '10px'}}>Welcome!</Typography>
                        <form onSubmit={handleSubmit} className='w100'>
                            <Box sx={{
                                display: 'flex',
                                width: '40%',
                                minWidth: '280px',}}>
                                <input type='email' name='email' id='email' placeholder='mail' className='input' value={email} onChange={e=>setEmail(e.target.value)} required />
                            </Box>
                            <Box sx={{
                                display: 'flex',
                                width: '40%',
                                minWidth: '280px',}}>
                                <input type='password' name='password' id='password' placeholder='password' className='input' value={password} onChange={e=>setPassword(e.target.value)} required />
                            </Box>
                            <GoogleSignIn/>
                            <Box sx={{
                                display: 'flex',
                                height: '40px',
                                width: '40%',}}>
                                <input type="submit" value='SignIn!' className='myButton fredokaFont' required />
                                <LinkRouter to={'/signup'} className='anchor festiveFont violetShadows'>
                                Don't have an account yet? go to SignUp!
                                </LinkRouter>
                            </Box>
                        </form>
                        </div>
                    </div>
        )
}
const mapDispatchToProps = {
    signInUser: userActions.signInUser
}
const mapStateToProps = (state) => {
    return {
        message: state.userReducers.message
    }
}
export default connect(mapStateToProps, mapDispatchToProps)(SignIn)
